from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0, "feedback": "external_services_path is None; cannot check Slack data"}

    slack_path = Path(external_services_path) / "slack_data.json"
    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}

    with open(slack_path) as f:
        data = json.load(f)

    # Find #acct-payroll-commissions channel
    channels = data.get("channels", {})
    target_channel_id = None
    for cid, cinfo in channels.items():
        if "acct-payroll-commissions" in (cinfo.get("name") or "").lower():
            target_channel_id = cid
            break

    if target_channel_id is None:
        return {"pass": False, "score": 0.0, "feedback": "Channel #acct-payroll-commissions not found in slack_data.json"}

    messages_dict = data.get("messages", {})
    channel_messages = messages_dict.get(target_channel_id, [])

    if not channel_messages:
        return {"pass": False, "score": 0.0, "feedback": f"No messages found in #acct-payroll-commissions (channel id: {target_channel_id})"}

    all_text = " ".join((m.get("text") or "").lower() for m in channel_messages)

    has_4505 = "4505" in all_text
    has_4507 = "4507" in all_text
    has_unwound_or_reversed = any(word in all_text for word in ["unwound", "reversed", "reversal", "unwind", "void", "voided"])
    has_not_posted = any(phrase in all_text for phrase in ["not posted", "not in deal log", "not in the deal log", "missing from deal log", "no deal log"])
    has_payroll_exclusion = any(phrase in all_text for phrase in ["cannot be included", "not include", "exclude", "cannot include", "can't include"])

    # Check for Olivia Mercer notification (Slack or email)
    olivia_notified_slack = "olivia" in all_text or "mercer" in all_text

    # Also check email notification to Olivia
    olivia_notified_email = False
    if external_services_path:
        mailbox_path = Path(external_services_path) / "mailbox.json"
        if mailbox_path.exists():
            with open(mailbox_path) as f:
                mail_data = json.load(f)
            sent = [e for e in mail_data.get("emails", []) if e.get("folder") == "Sent"]
            for email in sent:
                to = (email.get("to_addr") or "").lower()
                body = (email.get("body_text") or "").lower()
                if "olivia" in to or "mercer" in to or ("olivia" in body and ("4505" in body or "4507" in body)):
                    olivia_notified_email = True
                    break

    # Also check all slack messages for DM to Olivia
    olivia_notified_dm = False
    for cid, msgs in messages_dict.items():
        for msg in msgs:
            txt = (msg.get("text") or "").lower()
            if ("olivia" in txt or "mercer" in txt) and ("4505" in txt or "4507" in txt) and ("remove" in txt or "remov" in txt or "cannot" in txt or "not include" in txt):
                olivia_notified_dm = True
                break

    olivia_notified = olivia_notified_slack or olivia_notified_email or olivia_notified_dm

    checks = {
        "Deal 4505 mentioned": has_4505,
        "Deal 4507 mentioned": has_4507,
        "Unwound/reversed mentioned for 4505": has_unwound_or_reversed,
        "Not posted in deal log for 4507": has_not_posted,
        "Payroll exclusion stated": has_payroll_exclusion,
        "Olivia Mercer notified": olivia_notified
    }

    failed = [k for k, v in checks.items() if not v]
    passed = [k for k, v in checks.items() if v]

    if len(failed) == 0:
        return {"pass": True, "score": 1.0, "feedback": f"Slack message in #acct-payroll-commissions correctly flags deals 4505 and 4507, and Olivia Mercer is notified. Checks passed: {passed}"}

    # Partial pass: if both deals mentioned and at least some context
    if has_4505 and has_4507:
        score = 0.6
        return {"pass": False, "score": score, "feedback": f"Both deals mentioned in #acct-payroll-commissions but missing: {failed}"}

    return {"pass": False, "score": 0.1, "feedback": f"Slack message in #acct-payroll-commissions incomplete. Failed checks: {failed}"}

