from pathlib import Path
import json
import re


def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {"pass": False, "score": 0.0,
                "feedback": "external_services_path is None; cannot check mailbox"}

    mailbox_path = Path(external_services_path) / "mailbox.json"
    if not mailbox_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "mailbox.json not found"}

    with open(mailbox_path) as f:
        data = json.load(f)

    sent_emails = [e for e in data.get("emails", []) if e.get("folder") == "Sent"]
    hannah_emails = [
        e for e in sent_emails
        if "hannah.price@sunshineandsetauto.com" in (e.get("to_addr") or "")
    ]

    if not hannah_emails:
        return {"pass": False, "score": 0.0,
                "feedback": "No sent email to hannah.price@sunshineandsetauto.com found"}

    # Find an April email
    april_email = None
    for email in hannah_emails:
        body = (email.get("body_text") or "").lower()
        if "april" in body and ("commission" in body or "payroll" in body):
            april_email = email
            break

    if april_email is None:
        return {"pass": False, "score": 0.0,
                "feedback": "No April payroll/commission email found to Hannah Price"}

    body = (april_email.get("body_text") or "").lower()

    excluded_deals = {
        "4505": "unwound / posting reversed",
        "4507": "not posted in deal log",
    }

    improperly_included = []
    properly_excluded = []

    for deal, reason in excluded_deals.items():
        if deal not in body:
            properly_excluded.append(f"Deal {deal} ({reason}): not mentioned")
            continue

        lines_with_deal = [line for line in body.split("\n") if deal in line]
        is_commission_line = False
        is_exclusion_note = False
        for line in lines_with_deal:
            has_dollar = bool(re.search(r"\$[\d,]+", line))
            has_exclusion_language = any(
                w in line for w in [
                    "exclud", "remov", "unwound", "unwind", "reversed",
                    "not posted", "not include", "cannot", "ineligible",
                    "outside", "note:", "(note", "withheld", "held"
                ]
            )
            if has_exclusion_language:
                is_exclusion_note = True
            elif has_dollar and not has_exclusion_language:
                is_commission_line = True

        if is_commission_line and not is_exclusion_note:
            improperly_included.append(f"Deal {deal} ({reason})")
        else:
            properly_excluded.append(f"Deal {deal} ({reason})")

    if not improperly_included:
        return {"pass": True, "score": 1.0,
                "feedback": f"Both 4505 and 4507 correctly kept out of commission line items: {properly_excluded}"}

    score = round(len(properly_excluded) / len(excluded_deals), 2)
    return {
        "pass": False,
        "score": min(score, 0.5),
        "feedback": (
            f"Deal(s) improperly included as commission line items: {improperly_included}. "
            f"Correctly excluded: {properly_excluded}"
        ),
    }
